	@Test
	void planJoinOrderSupportsBindingSetAssignmentsAndSimpleFilters() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		Resource s1 = VF.createIRI("urn:s1");
		Resource s2 = VF.createIRI("urn:s2");
		IRI follows = VF.createIRI("urn:follows");
		IRI name = VF.createIRI("urn:name");
		store.add(VF.createStatement(s1, follows, VF.createIRI("urn:x1")));
		store.add(VF.createStatement(s2, follows, VF.createIRI("urn:x2")));
		store.add(VF.createStatement(s1, name, VF.createLiteral("alice")));
		store.add(VF.createStatement(s2, name, VF.createLiteral("bob")));

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, config()));
		estimator.rebuild();

		BindingSetAssignment bindings = new BindingSetAssignment();
		QueryBindingSet row1 = new QueryBindingSet();
		row1.addBinding("s", s1);
		QueryBindingSet row2 = new QueryBindingSet();
		row2.addBinding("s", s2);
		bindings.setBindingSets(List.<BindingSet>of(row1, row2));

		StatementPattern followsPattern = pattern("s", follows, "x");
		StatementPattern namePattern = pattern("s", name, "name");
		Filter filteredName = new Filter(namePattern,
				new Compare(Var.of("name"), new ValueConstant(VF.createLiteral("alice")), Compare.CompareOp.EQ));

		List<TupleExpr> args = List.of(bindings, followsPattern, filteredName);
		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.GREEDY);

		assertTrue(plan.isPresent(), "Expected planner to support BindingSetAssignment + simple Filter join arguments");
		List<TupleExpr> orderedArgs = plan.get().getOrderedArgs();
		assertEquals(args.size(), orderedArgs.size());
		assertTrue(orderedArgs.containsAll(args));
	}

