	@Test
	void planJoinOrderPreparesSelectiveEndpointDomainsBeforeBroadBridge() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI rdfType = VF.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
		IRI drugType = VF.createIRI("urn:Drug");
		IRI targets = VF.createIRI("urn:targets");
		IRI inPathway = VF.createIRI("urn:inPathway");
		List<Resource> targetValues = new ArrayList<>();
		for (int i = 0; i < 40; i++) {
			Resource target = VF.createIRI("urn:target:" + i);
			targetValues.add(target);
			store.add(VF.createStatement(target, inPathway, VF.createIRI("urn:pathway:" + (i % 8))));
		}
		for (int i = 0; i < 800; i++) {
			Resource drug = VF.createIRI("urn:drug:" + i);
			store.add(VF.createStatement(drug, rdfType, drugType));
			for (int j = 0; j < 5; j++) {
				Resource target = targetValues.get((i + j) % targetValues.size());
				store.add(VF.createStatement(drug, targets, target));
			}
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, config()));
		estimator.rebuild();

		StatementPattern typePattern = new StatementPattern(Var.of("drug"), Var.of("rdfType", rdfType),
				Var.of("drugType", drugType));
		StatementPattern targetsPattern = pattern("drug", targets, "target");
		StatementPattern pathwayPattern = pattern("target", inPathway, "pathway");
		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(
				List.of(typePattern, targetsPattern, pathwayPattern), Set.of(),
				JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING);

		assertTrue(plan.isPresent(), "Expected planner to handle broad bridge with selective endpoint domains");
		List<TupleExpr> orderedArgs = plan.get().getOrderedArgs();
		int typeIndex = orderedArgs.indexOf(typePattern);
		int targetsIndex = orderedArgs.indexOf(targetsPattern);
		int pathwayIndex = orderedArgs.indexOf(pathwayPattern);
		assertTrue(typeIndex >= 0 && targetsIndex >= 0 && pathwayIndex >= 0,
				"Expected all endpoint and bridge patterns in the plan: " + orderedArgs);
		assertTrue(targetsIndex > 0,
				"The broad targets bridge should not be used as the seed before endpoint domains: " + orderedArgs);
		assertTrue(typeIndex < targetsIndex || pathwayIndex < targetsIndex,
				"At least one endpoint domain should be prepared before probing the broad targets bridge: "
						+ orderedArgs);
		assertPlanWorkMatchesStepSum(plan.get());
	}

	@Test
	void memoPlannerKeepsEndpointPreparationForPharmaBridgeShape() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI rdfType = VF.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
		IRI drugType = VF.createIRI("urn:Drug");
		IRI targets = VF.createIRI("urn:targets");
		IRI inPathway = VF.createIRI("urn:inPathway");
		List<Resource> targetValues = new ArrayList<>();
		for (int i = 0; i < 666; i++) {
			Resource target = VF.createIRI("urn:target:" + i);
			targetValues.add(target);
			store.add(VF.createStatement(target, inPathway, VF.createIRI("urn:pathway:" + (i % 140))));
		}
		for (int i = 0; i < 5006; i++) {
			Resource drug = VF.createIRI("urn:drug:" + i);
			store.add(VF.createStatement(drug, rdfType, drugType));
			for (int j = 0; j < 4; j++) {
				store.add(VF.createStatement(drug, targets, targetValues.get((i * 4 + j) % targetValues.size())));
			}
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, productionThemeConfig()));
		estimator.rebuild();

		BindingSetAssignment markerValues = singleVariableValues("marker",
				List.of(VF.createIRI("urn:marker:3"), VF.createIRI("urn:marker:4")));
		StatementPattern typePattern = new StatementPattern(Var.of("drug"), Var.of("rdfType", rdfType),
				Var.of("drugType", drugType));
		StatementPattern targetsPattern = pattern("drug", targets, "target");
		StatementPattern pathwayPattern = pattern("target", inPathway, "pathway");
		JoinFactorCostModel costModel = directLookupAwareCostModel(typePattern, targetsPattern, pathwayPattern);

		JoinOrderPlanner.JoinOrderPlan plan = estimator
				.planJoinOrderAttempt(List.of(markerValues, typePattern, targetsPattern, pathwayPattern), Set.of(),
						JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, costModel, List.of())
				.getPlan()
				.orElseThrow();

		List<TupleExpr> orderedArgs = plan.getOrderedArgs();
		assertEquals(4, orderedArgs.size(), "Planner should keep every original factor");
		assertTrue(orderedArgs.containsAll(List.of(typePattern, pathwayPattern, targetsPattern, markerValues)),
				"PHARMA endpoint domains should survive the memo frontier before the broad targets bridge");
		assertTrue(orderedArgs.indexOf(targetsPattern) > 0,
				"The broad targets bridge should not be used as the seed before endpoint domains");
		assertTrue(orderedArgs.indexOf(markerValues) > orderedArgs.indexOf(targetsPattern),
				"Disconnected marker values should not split the endpoint-domain bridge");
		assertTrue(orderedArgs.indexOf(pathwayPattern) < orderedArgs.indexOf(markerValues),
				"Pathway endpoint domain should be planned before the disconnected marker values");
		assertTrue(orderedArgs.indexOf(typePattern) < orderedArgs.indexOf(markerValues),
				"Drug type guard should be planned before the disconnected marker values");
	}

	@Test
	void planJoinOrderHandlesMultipleJoinVariablesWithoutGlobalCommonVar() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI pA = VF.createIRI("urn:pA");
		IRI pB = VF.createIRI("urn:pB");
		IRI pC = VF.createIRI("urn:pC");

		for (int i = 0; i < 8; i++) {
			Resource s = VF.createIRI("urn:s" + i);
			IRI o = VF.createIRI("urn:o" + i);
			IRI x = VF.createIRI("urn:x" + i);
			IRI z = VF.createIRI("urn:z" + i);
			store.add(VF.createStatement(s, pA, o));
			store.add(VF.createStatement(s, pB, x));
			store.add(VF.createStatement(x, pC, z));
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, config()));
		estimator.rebuild();

		StatementPattern a = pattern("s", pA, "o");
		StatementPattern b = pattern("s", pB, "x");
		StatementPattern c = pattern("x", pC, "z");
		List<TupleExpr> args = List.of(a, b, c);

		Optional<JoinOrderPlanner.JoinOrderPlan> dpPlan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING);
		Optional<JoinOrderPlanner.JoinOrderPlan> greedyPlan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.GREEDY);

		assertTrue(dpPlan.isPresent(), "Expected dynamic programming planner to produce a join order");
		assertEquals(SketchBasedJoinEstimator.SketchPlannerPath.ROBUST_USED, estimator.lastJoinOrderPlannerPath(),
				"Supported flat segments should go through the robust planner");
		assertTrue(greedyPlan.isPresent(), "Expected greedy planner to produce a join order");
		assertEquals(args.size(), dpPlan.get().getOrderedArgs().size());
		assertTrue(dpPlan.get().getOrderedArgs().containsAll(args));
		assertEquals(args.size(), greedyPlan.get().getOrderedArgs().size());
		assertTrue(greedyPlan.get().getOrderedArgs().containsAll(args));
		assertEquals(SketchBasedJoinEstimator.SketchPlannerPath.ROBUST_USED, estimator.lastJoinOrderPlannerPath(),
				"Supported flat segments should go through the robust planner");
	}

	@Test
	void planJoinOrderSupportsMultiSharedValuesClique() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI follows = VF.createIRI("urn:follows");
		List<Resource> users = List.of(VF.createIRI("urn:user:0"), VF.createIRI("urn:user:1"),
				VF.createIRI("urn:user:2"));
		for (Resource left : users) {
			for (Resource right : users) {
				if (!left.equals(right)) {
					store.add(VF.createStatement(left, follows, right));
				}
			}
		}

		BindingSetAssignment userPairs = new BindingSetAssignment();
		List<BindingSet> pairRows = new ArrayList<>();
		for (Resource u1 : users) {
			for (Resource u2 : users) {
				if (!u1.equals(u2)) {
					QueryBindingSet row = new QueryBindingSet();
					row.addBinding("u1", u1);
					row.addBinding("u2", u2);
					pairRows.add(row);
				}
			}
		}
		userPairs.setBindingSets(pairRows);

		BindingSetAssignment u3Values = new BindingSetAssignment();
		List<BindingSet> u3Rows = new ArrayList<>();
		for (Resource user : users) {
			QueryBindingSet row = new QueryBindingSet();
			row.addBinding("u3", user);
			u3Rows.add(row);
		}
		u3Values.setBindingSets(u3Rows);

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, config()));
		estimator.rebuild();

		StatementPattern u1FollowsU2 = pattern("u1", follows, "u2");
		StatementPattern u1FollowsU3 = pattern("u1", follows, "u3");
		StatementPattern u2FollowsU1 = pattern("u2", follows, "u1");
		StatementPattern u3FollowsU1 = pattern("u3", follows, "u1");
		StatementPattern u2FollowsU3 = pattern("u2", follows, "u3");
		StatementPattern u3FollowsU2 = pattern("u3", follows, "u2");
		List<TupleExpr> args = List.of(userPairs, u3Values, u1FollowsU2, u1FollowsU3, u2FollowsU1,
				u3FollowsU1, u2FollowsU3, u3FollowsU2);

		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.GREEDY);

		assertTrue(plan.isPresent(), "Dense multi-shared VALUES cliques should stay on the sketch planner path");
		assertEquals(SketchBasedJoinEstimator.SketchPlannerPath.ROBUST_USED, estimator.lastJoinOrderPlannerPath(),
				"Multi-shared VALUES cliques should no longer fall back to clone-based greedy scoring");
		assertTrue(plan.get().getOrderedArgs().get(0) instanceof BindingSetAssignment,
				"A bounded VALUES factor should anchor the dense clique before broad edge scans");
		assertTrue(plan.get().getOrderedArgs().containsAll(args));
	}

