	@Test
	void planJoinOrderSeedsFromMostSelectiveCorrelatedChainEnd() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI hasArm = VF.createIRI("urn:hasArm");
		IRI hasResult = VF.createIRI("urn:hasResult");
		IRI biomarker = VF.createIRI("urn:biomarker");

		for (int trialIndex = 0; trialIndex < 8; trialIndex++) {
			Resource trial = VF.createIRI("urn:trial:" + trialIndex);
			for (int armIndex = 0; armIndex < 50; armIndex++) {
				Resource arm = VF.createIRI("urn:arm:" + trialIndex + ':' + armIndex);
				Resource result = VF.createIRI("urn:result:" + trialIndex + ':' + armIndex);
				Resource marker = VF.createIRI("urn:marker:" + trialIndex + ':' + armIndex);
				store.add(VF.createStatement(trial, hasArm, arm));
				store.add(VF.createStatement(arm, hasResult, result));
				store.add(VF.createStatement(result, biomarker, marker));
			}
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, config()));
		estimator.rebuild();

		StatementPattern trialArmPattern = pattern("trial", hasArm, "arm");
		StatementPattern armResultPattern = pattern("arm", hasResult, "result");
		StatementPattern biomarkerPattern = pattern("result", biomarker, "marker");
		Set<String> outerBoundVars = Set.of("trial", "marker");

		SketchBasedJoinEstimator.TuplePlanEstimate trialArmEstimate = estimator
				.planEstimateForJoinOrdering(trialArmPattern, outerBoundVars);
		SketchBasedJoinEstimator.TuplePlanEstimate armResultEstimate = estimator
				.planEstimateForJoinOrdering(armResultPattern, outerBoundVars);
		SketchBasedJoinEstimator.TuplePlanEstimate biomarkerEstimate = estimator
				.planEstimateForJoinOrdering(biomarkerPattern, outerBoundVars);

		SketchBasedJoinEstimator.JoinStepEstimate biomarkerFirst = estimator
				.estimateJoinStepForJoinOrdering(biomarkerEstimate, armResultEstimate);
		SketchBasedJoinEstimator.JoinStepEstimate trialFirst = estimator
				.estimateJoinStepForJoinOrdering(trialArmEstimate, armResultEstimate);

		assertTrue(biomarkerFirst.outputRows() < trialFirst.outputRows(),
				"Bound biomarker subset should stay smaller than the bound trial subset when extended through result");

		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(
				List.of(trialArmPattern, armResultPattern, biomarkerPattern),
				outerBoundVars,
				JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING);

		assertTrue(plan.isPresent(), "Expected planner to produce a correlated-chain plan");
		assertEquals(biomarkerPattern, plan.get().getOrderedArgs().get(0),
				"Planner should seed from the most selective correlated chain end");
	}

	@Test
	void planJoinOrderUsesDeferredFilterVarsProducedByCandidate() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI rdfType = VF.createIRI("urn:rdfType");
		IRI clinicalTrial = VF.createIRI("urn:ClinicalTrial");
		IRI studiesDisease = VF.createIRI("urn:studiesDisease");
		IRI hasArm = VF.createIRI("urn:hasArm");
		IRI hasResult = VF.createIRI("urn:hasResult");
		IRI responseRate = VF.createIRI("urn:responseRate");
		IRI armDrug = VF.createIRI("urn:armDrug");

		for (int trialIndex = 0; trialIndex < 100; trialIndex++) {
			Resource trial = VF.createIRI("urn:trial:" + trialIndex);
			store.add(VF.createStatement(trial, rdfType, clinicalTrial));
			store.add(VF.createStatement(trial, studiesDisease, VF.createIRI("urn:disease:" + trialIndex)));
			for (int armIndex = 0; armIndex < 3; armIndex++) {
				Resource arm = VF.createIRI("urn:arm:" + trialIndex + ':' + armIndex);
				Resource result = VF.createIRI("urn:result:" + trialIndex + ':' + armIndex);
				store.add(VF.createStatement(trial, hasArm, arm));
				store.add(VF.createStatement(arm, hasResult, result));
				store.add(VF.createStatement(result, responseRate, VF.createLiteral(armIndex == 0 ? 0.7d : 0.2d)));
				store.add(VF.createStatement(arm, armDrug, VF.createIRI("urn:drug:" + trialIndex + ':' + armIndex)));
			}
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, config()));
		estimator.rebuild();

		StatementPattern trialTypePattern = new StatementPattern(Var.of("trial"), Var.of("rdfType", rdfType),
				Var.of("clinicalTrial", clinicalTrial));
		StatementPattern studiesDiseasePattern = pattern("trial", studiesDisease, "disease");
		StatementPattern trialArmPattern = pattern("trial", hasArm, "arm");
		StatementPattern armResultPattern = pattern("arm", hasResult, "result");
		StatementPattern responseRatePattern = pattern("result", responseRate, "rate");
		StatementPattern armDrugPattern = pattern("arm", armDrug, "drug");
		List<TupleExpr> args = List.of(trialTypePattern, studiesDiseasePattern, trialArmPattern, armResultPattern,
				responseRatePattern, armDrugPattern);
		List<JoinOrderPlanner.FilterConstraint> deferredFilters = List.of(
				new JoinOrderPlanner.FilterConstraint(Set.of("rate"), 0.39d, 0, "?rate > 0.6", "learned_filter",
						300L));

		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, SketchBasedJoinEstimator.JoinOrderWorkAdjuster.NO_OP,
				deferredFilters);

		assertTrue(plan.isPresent(), "Expected planner to produce a clinical-trial chain plan");
		assertEquals(args.size(), plan.get().getOrderedArgs().size());
		assertTrue(plan.get().getOrderedArgs().contains(responseRatePattern),
				"Candidate-produced filter variables should keep the deferred-filter factor in the robust plan");
		assertTrue(plan.get()
				.getSummaryStringMetrics()
				.get(TelemetryMetricNames.OPTIMIZER_RUNTIME_FEEDBACK)
				.contains("sources={learned_filter=1}"),
				"Expected runtime feedback source diagnostics: "
						+ plan.get().getSummaryStringMetrics());
		assertTrue(plan.get()
				.getSummaryStringMetrics()
				.get(TelemetryMetricNames.OPTIMIZER_RUNTIME_FEEDBACK)
				.contains("totalEvidence=300"),
				"Expected runtime feedback evidence diagnostics: "
						+ plan.get().getSummaryStringMetrics());
		assertTrue(plan.get()
				.getSummaryDoubleMetrics()
				.get(TelemetryMetricNames.OPTIMIZER_RUNTIME_FEEDBACK_CONFIDENCE) > 0.8d,
				"Expected runtime feedback confidence diagnostics: " + plan.get().getSummaryDoubleMetrics());
		assertPlanWorkMatchesStepSum(plan.get());
	}

